class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        def is_beautiful(x):
            if x % k != 0:
                return False
            s = str(x)
            even = sum(1 for c in s if int(c) % 2 == 0)
            return even == len(s) - even
        return sum(1 for x in range(low, high + 1) if is_beautiful(x))

