class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        def count_up_to(x):
            if x <= 0:
                return 0
            s = str(x)
            n = len(s)
            memo = {}
            def rec(pos, diff, rem, tight, started):
                if pos == n:
                    return 1 if (started and diff == 0 and rem == 0) else 0
                key = (pos, diff, rem, tight, started)
                if key in memo:
                    return memo[key]
                limit = int(s[pos]) if tight else 9
                total = 0
                for d in range(0, limit + 1):
                    nd_tight = tight and d == limit
                    nd_started = started or d != 0
                    if not nd_started:
                        total += rec(pos + 1, diff, rem, nd_tight, nd_started)
                    else:
                        nd_diff = diff + (1 if d % 2 == 0 else -1)
                        nd_rem = (rem * 10 + d) % k
                        total += rec(pos + 1, nd_diff, nd_rem, nd_tight, nd_started)
                memo[key] = total
                return total
            return rec(0, 0, 0, True, False)
        return count_up_to(high) - count_up_to(low - 1)

