var numberOfBeautifulIntegers = function(low, high, k) {
    function countUpTo(x) {
        if (x <= 0) return 0;
        const s = String(x);
        const n = s.length;
        const memo = new Map();
        function rec(pos, diff, rem, tight, started) {
            if (pos === n) {
                return (started && diff === 0 && rem === 0) ? 1 : 0;
            }
            const key = pos + '_' + diff + '_' + rem + '_' + (tight ? 1 : 0) + '_' + (started ? 1 : 0);
            if (memo.has(key)) return memo.get(key);
            const limit = tight ? Number(s[pos]) : 9;
            let total = 0;
            for (let d = 0; d <= limit; d++) {
                const ndTight = tight && d === limit;
                const ndStarted = started || d !== 0;
                if (!ndStarted) {
                    total += rec(pos + 1, diff, rem, ndTight, ndStarted);
                } else {
                    const ndDiff = diff + (d % 2 === 0 ? 1 : -1);
                    const ndRem = (rem * 10 + d) % k;
                    total += rec(pos + 1, ndDiff, ndRem, ndTight, ndStarted);
                }
            }
            memo.set(key, total);
            return total;
        }
        return rec(0, 0, 0, true, false);
    }
    return countUpTo(high) - countUpTo(low - 1);
};
